INSERT INTO `blocks` (`id`, `room_id`, `name`, `topic`, `status`, `loop_infinite`, `is_tips_block`) VALUES
(1,1,'Dicas dos Nutricionistas','Dicas técnicas dos nutricionistas administradores. Loop infinito, intercalado randomicamente.','running',1,1),
